INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (401, 24, "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！", 2, 0.0, 10046, 102301, "2020/07/31 12:00:00", 0.0, 24001, 0.0, 2, "アヤネ", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (402, 24, "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！", 2, 2.21, 10046, 102301, "2020/07/31 12:00:00", 0.0, 24002, 0.0, 1, "アヤネ", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (403, 24, "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！", 2, 0.0, 10046, 102301, "2020/07/31 12:00:00", 0.0, 24003, 0.0, 2, "アヤネ", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (701, 24, "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！", 1, 1.99, 10046, 192201, "2020/07/31 12:00:00", 0.0, 24004, 0.0, 2, "アサヒ", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (702, 24, "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ", 2, 2.21, 10046, 192201, "2020/07/31 12:00:00", 0.0, 24005, 0.0, 1, "アサヒ", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (703, 24, "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！", 1, 3.33, 10046, 192201, "2020/07/31 12:00:00", 0.0, 24006, 0.0, 2, "アサヒ", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (801, 24, "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな", 2, 0.0, 10046, 192301, "2020/07/31 12:00:00", 0.0, 24007, 0.0, 2, "部員３", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (802, 24, "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる", 2, 2.68, 10046, 192301, "2020/07/31 12:00:00", 0.0, 24008, 0.0, 1, "部員３", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (803, 24, "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！", 2, 0.0, 10046, 192301, "2020/07/31 12:00:00", 0.0, 24009, 0.0, 2, "部員３", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (501, 24, "やった！", 1, 0.0, 10046, 192501, "2020/07/31 12:00:00", 0.0, 24010, 0.0, 1, "", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (502, 24, "勝ったよ！", 1, 0.0, 10046, 192501, "2020/07/31 12:00:00", 0.0, 24011, 0.0, 1, "", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (503, 24, "いい調子！", 1, 0.0, 10046, 192501, "2020/07/31 12:00:00", 0.0, 24012, 0.0, 1, "", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (111, 24, "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね", 2, 5.33, 10046, 113501, "2020/07/31 12:00:00", 0.0, 24013, 0.0, 6, "ミサト", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (112, 24, "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！", 2, 6.85, 10046, 113501, "2020/07/31 12:00:00", 0.0, 24014, 0.0, 1, "ミサト", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (113, 24, "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！", 2, 3.0, 10046, 113501, "2020/07/31 12:00:00", 0.0, 24015, 0.0, 1, "ミサト", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (611, 24, "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！", 2, 6.11, 10046, 192401, "2020/07/31 12:00:00", 0.0, 24016, 0.0, 1, "ダイチ", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (612, 24, "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！", 2, 6.75, 10046, 192401, "2020/07/31 12:00:00", 0.0, 24017, 0.0, 1, "ダイチ", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (613, 24, "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！", 2, 0.0, 10046, 192401, "2020/07/31 12:00:00", 0.0, 24018, 0.0, 2, "ダイチ", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (211, 24, "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！", 1, 4.52, 10046, 113401, "2020/07/31 12:00:00", 0.0, 24019, 0.0, 2, "ハツネ", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (212, 24, "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！", 1, 3.89, 10046, 113401, "2020/07/31 12:00:00", 0.0, 24020, 0.0, 2, "ハツネ", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (213, 24, "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…", 2, 13.49, 10046, 113401, "2020/07/31 12:00:00", 0.0, 24021, 0.0, 1, "ハツネ", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (311, 24, "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ", 2, 3.17, 10046, 106501, "2020/07/31 12:00:00", 0.0, 24022, 0.0, 1, "カヤ", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (312, 24, "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ", 2, 4.42, 10046, 106501, "2020/07/31 12:00:00", 0.0, 24023, 0.0, 1, "カヤ", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (313, 24, "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！", 1, 2.89, 10046, 106501, "2020/07/31 12:00:00", 0.0, 24024, 0.0, 6, "カヤ", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (421, 24, "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！", 3, 3.71, 10046, 102301, "2020/07/31 12:00:00", 0.0, 24025, 0.0, 4, "アヤネ", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (721, 24, "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！", 1, 5.1, 10046, 192201, "2020/07/31 12:00:00", 0.0, 24026, 0.0, 2, "アサヒ", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (821, 24, "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ", 3, 4.34, 10046, 192301, "2020/07/31 12:00:00", 0.0, 24027, 0.0, 1, "部員３", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (521, 24, "いい勝負だったよ\nまたやろうね", 1, 0.0, 10046, 192501, "2020/07/31 12:00:00", 0.0, 24028, 0.0, 1, "", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (101, 24, "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～", 2, 5.62, 10046, 113501, "2020/07/31 12:00:00", -360.0, 24029, 0.0, 1, "ミサト", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (102, 24, "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！", 2, 9.58, 10046, 113501, "2020/07/31 12:00:00", -360.0, 24030, 0.0, 1, "ミサト", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (103, 24, "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね", 2, 0.0, 10046, 113501, "2020/07/31 12:00:00", -360.0, 24031, 0.0, 2, "ミサト", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (104, 24, "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！", 1, 9.13, 10046, 113501, "2020/07/31 12:00:00", -360.0, 24032, 0.0, 2, "ミサト", "2030/12/17 14:59:59");
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES (105, 24, "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！", 2, 8.27, 10046, 113501, "2020/07/31 12:00:00", -360.0, 24033, 0.0, 1, "ミサト", "2030/12/17 14:59:59");
